{
  "parameters": {
    "effect": {
      "type": "String",
      "defaultValue": "Audit",
      "allowedValues": ["Audit", "Deny", "Disabled"],
      "metadata": { "displayName": "Effect" }
    },
    "allowedLocations": {
      "type": "Array",
      "defaultValue": ["eastus", "eastus2"],
      "metadata": { "displayName": "Allowed regions", "strongType": "location" }
    },
    "workspaceResourceId": {
      "type": "String",
      "metadata": { "displayName": "Log Analytics workspace ID", "strongType": "omsWorkspace" }
    }
  },
  "policyRule": {
    "if": {
      "field": "location",
      "notIn": "[parameters('allowedLocations')]"
    },
    "then": {
      "effect": "[parameters('effect')]"
    }
  }
}

// field() used to pass evaluated VM properties into a DINE deployment
{
  "then": {
    "effect": "DeployIfNotExists",
    "details": {
      "type": "Microsoft.Compute/virtualMachines/extensions",
      "roleDefinitionIds": [
        "/providers/Microsoft.Authorization/roleDefinitions/b24988ac-6180-42a0-ab88-20f7382dd24c"
      ],
      "existenceCondition": {
        "field": "Microsoft.Compute/virtualMachines/extensions/type",
        "equals": "AzureMonitorWindowsAgent"
      },
      "deployment": {
        "properties": {
          "mode": "incremental",
          "parameters": {
            "vmName":       { "value": "[field('name')]" },
            "vmLocation":   { "value": "[field('location')]" },
            "vmResourceId": { "value": "[field('id')]" },
            "osType":       { "value": "[field('Microsoft.Compute/virtualMachines/storageProfile.osDisk.osType')]" },
            "workspaceId":  { "value": "[parameters('workspaceResourceId')]" }
          },
          "template": { "/* ARM template here */": "" }
        }
      }
    }
  }
}

// resourceGroup() — test the resource group name and tags

// 1. Test the resource group name pattern
{
  "value": "[resourceGroup().name]",
  "like": "rg-prod-*"
}

// 2. Test that the resource group has a specific tag
{
  "value": "[resourceGroup().tags['CostCenter']]",
  "exists": "true"
}

// 3. Require resources to inherit the resource group CostCenter tag
{
  "if": {
    "allOf": [
      {
        "field": "tags['CostCenter']",
        "notEquals": "[resourceGroup().tags['CostCenter']]"
      },
      {
        "value": "[resourceGroup().tags['CostCenter']]",
        "notEquals": ""
      }
    ]
  },
  "then": { "effect": "modify", "details": { "/* modify ops to copy tag */": "" } }
}

// subscription() — test subscription ID or name
{
  "value": "[subscription().subscriptionId]",
  "notIn": "[parameters('blockedSubscriptionIds')]"
}

// subscription() properties available: subscriptionId, tenantId, displayName, state
{
  "value": "[subscription().displayName]",
  "like": "Prod*"
}

// concat() to build a dynamic field path from a parameter
{
  "parameters": {
    "tagName": {
      "type": "String",
      "metadata": { "displayName": "Required tag name" }
    }
  },
  "policyRule": {
    "if": {
      "not": {
        "field": "[concat('tags[', parameters('tagName'), ']')]",
        "exists": "true"
      }
    },
    "then": { "effect": "deny" }
  }
}

// concat() to build a resource type path
// Not needed in field conditions (path is a literal string) but useful in
// DINE deployment templates to build resource names or resource IDs:
{
  "name": "[concat(parameters('vmName'), '/', variables('extensionName'))]"
}

// Normalize a tag value before comparing
{
  "value": "[toLower(field('tags[Environment]'))]",
  "notIn": ["prod", "production", "prd"]
}
// Without toLower, 'Prod' and 'PROD' and 'prod' are treated differently

// Use in value condition with resourceGroup tag
{
  "value": "[toLower(resourceGroup().tags['environment'])]",
  "equals": "prod"
}

// toUpper is less common but useful when comparing to uppercase reference strings
{
  "value": "[toUpper(field('Microsoft.Compute/virtualMachines/hardwareProfile.vmSize'))]",
  "like": "STANDARD_D*"
}

// utcNow() in a DINE ARM deployment template — stamp a tag on the deployed resource
{
  "template": {
    "$schema": "https://schema.management.azure.com/schemas/2019-04-01/deploymentTemplate.json#",
    "contentVersion": "1.0.0.0",
    "parameters": {
      "currentDatetime": {
        "type": "string",
        "defaultValue": "[utcNow()]"
        // utcNow() is ONLY valid as a parameter defaultValue inside a template
        // It cannot be used inline in a resource property value
      }
    },
    "resources": [
      {
        "type": "Microsoft.Compute/virtualMachines",
        "name": "[parameters('vmName')]",
        "tags": {
          "PolicyRemediatedAt": "[parameters('currentDatetime')]"
        }
      }
    ]
  }
}

// Note: utcNow() format options
// [utcNow()]           -> '20230601T120000Z' (compact ISO)
// [utcNow('d')]        -> '06/01/2023' (date only)
// [utcNow('yyyy-MM-dd')] -> '2023-06-01' (ISO date)
